3	namespace App\Livewire\Auth;
4	
5	use Illuminate\Support\Facades\Http;
6	use Illuminate\Support\Facades\Session;
7	use Livewire\Attributes\Layout;
8	use Livewire\Attributes\Title;
9	use Livewire\Component;
10	
11	#[Layout('layouts.app')]
12	#[Title('Sign In — ServicePlatform')]
13	class Login extends Component
14	{
15	    public string $username = '';
16	    public string $password = '';
17	    public string $error = '';
18	
19	    /**
20	     * API-decoupled login: posts credentials to /api/auth/login and stores
21	     * the returned access token in the web session. The component never
22	     * touches AuthService or the User model directly.
23	     */
24	    public function login(): void
25	    {
26	        $this->validate([
27	            'username' => 'required|string',
28	            'password' => 'required|string',
29	        ]);
30	
31	        $baseUrl = config('app.url', 'http://localhost:8080');
32	        $resp = Http::baseUrl($baseUrl . '/api')
33	            ->acceptJson()
34	            ->timeout(15)
35	            ->post('/auth/login', [
36	                'username' => $this->username,
37	                'password' => $this->password,
38	            ]);
39	
40	        if ($resp->failed() || empty($resp->json('access_token'))) {
41	            $this->error = 'Invalid username or password.';
42	            return;
43	        }
44	
45	        $token = $resp->json('access_token');
46	        Session::put('jwt_token', $token);
47	
48	        // Decode the JWT payload (the API returns role/sub server-side, but we
49	        // also peek at the unverified body for session metadata — the token
50	        // itself is the source of truth, this is just for display).
51	        $parts = explode('.', $token);
52	        if (count($parts) >= 2) {
53	            $payload = json_decode(base64_decode($parts[1]), true) ?? [];
54	            Session::put('auth_user_id', $payload['sub'] ?? null);
55	            Session::put('auth_role', $payload['role'] ?? 'user');
56	        }
57	        Session::put('auth_user_name', $resp->json('user.full_name', $this->username));
58	
59	        $this->redirect('/dashboard');
60	    }
61	
62	    public function render()
63	    {
64	        return view('livewire.auth.login');
65	    }
66	}
