11	#[Layout('layouts.app')]
12	#[Title('Commission Report')]
13	class CommissionReport extends Component
14	{
15	    #[Url] public string $dateFrom = '';
16	    #[Url] public string $dateTo = '';
17	
18	    public function mount(): void
19	    {
20	        $this->dateFrom = $this->dateFrom ?: now()->startOfMonth()->toDateString();
21	        $this->dateTo = $this->dateTo ?: now()->toDateString();
22	    }
23	
24	    public function render(SettlementService $settlements)
25	    {
26	        $user = auth()->user() ?? request()->attributes->get('auth_user');
27	        if (!$user) abort(401);
28	        if (!$user->isAdmin() && $user->role !== 'group-leader') abort(403);
29	
30	        // Reads centralised in the application service for tenant scoping.
31	        $commissions = $settlements->listCommissionsForUser($user, $this->dateFrom ?: null, $this->dateTo ?: null);
32	        $totals = [
33	            'revenue'    => $commissions->sum('attributed_revenue'),
34	            'commission' => $commissions->sum('commission_amount'),
35	            'orders'     => $commissions->sum('order_count'),
36	        ];
37	        $attributedOrders = $settlements->listAttributedOrdersForLeader($user, $this->dateFrom ?: null, $this->dateTo ?: null);
38	
39	        return view('livewire.settlement.commission-report', [
40	            'commissions' => $commissions,
41	            'totals' => $totals,
42	            'attributedOrders' => $attributedOrders,
43	        ]);
44	    }
45	}
