8	use Livewire\Component;
9	
10	#[Layout('layouts.app')]
11	#[Title('Order Detail')]
12	class OrderShow extends Component
13	{
14	    use UsesApiClient;
15	
16	    public int $orderId;
17	    public string $cancelReason = '';
18	    public string $error = '';
19	
20	    public function mount(int $orderId): void
21	    {
22	        $this->orderId = $orderId;
23	        // Authorize on first load by going through the API. The
24	        // OrderApiController already runs Gate::authorize('view', ...),
25	        // so we get authorization parity with REST consumers without
26	        // touching the model directly here.
27	        $resp = $this->api()->get("/orders/{$orderId}");
28	        if ($resp->status() === 403) {
29	            abort(403, 'You are not authorized to view this order.');
30	        }
31	        if ($resp->status() === 404) {
32	            abort(404);
33	        }
34	        if ($resp->failed()) {
35	            abort(500, 'Failed to load order.');
36	        }
37	    }
38	
39	    public function checkIn(): void { $this->callTransition('checked_in'); }
40	    public function checkOut(): void { $this->callTransition('checked_out'); }
41	    public function complete(): void { $this->callTransition('completed'); }
42	
43	    public function cancel(): void
44	    {
45	        // Authorization is enforced by the API endpoint via Gate::authorize.
46	        $this->callTransition('cancelled', $this->cancelReason ?: null);
47	    }
48	
49	    public function refund(): void
50	    {
51	        $resp = $this->api()->post("/orders/{$this->orderId}/refund", ['reason' => 'Customer requested']);
52	        if ($resp->status() === 403) {
53	            $this->error = 'You are not authorized to refund this order.';
54	            return;
55	        }
56	        if ($resp->failed()) { $this->error = $resp->json('message') ?? 'Refund failed.'; }
57	    }
58	
59	    public function markUnavailable(): void
60	    {
61	        $resp = $this->api()->post("/orders/{$this->orderId}/mark-unavailable");
62	        if ($resp->status() === 403) {
63	            $this->error = 'You are not authorized.';
64	            return;
65	        }
66	        if ($resp->failed()) { $this->error = $resp->json('message') ?? 'Failed.'; }
67	    }
68	
69	    private function callTransition(string $status, ?string $reason = null): void
70	    {
71	        $resp = $this->api()->post("/orders/{$this->orderId}/transition", [
72	            'status' => $status,
73	            'reason' => $reason,
74	        ]);
75	        if ($resp->status() === 403) {
76	            $this->error = 'You are not authorized to perform this operational action.';
77	            return;
78	        }
79	        if ($resp->failed()) { $this->error = $resp->json('message') ?? 'Transition failed.'; }
80	    }
81	
82	    public function render()
83	    {
84	        // Read through the API so authorization is enforced uniformly
85	        // with REST consumers — no direct service or model access.
86	        $resp = $this->api()->get("/orders/{$this->orderId}");
87	        if ($resp->status() === 403) {
88	            abort(403);
89	        }
90	        if ($resp->failed()) {
91	            abort($resp->status() ?: 500);
92	        }
93	        $order = $resp->json('data');
94	        return view('livewire.orders.order-show', ['order' => $order]);
95	    }
96	}
