5	use App\Livewire\Concerns\UsesApiClient;
6	use Illuminate\Pagination\LengthAwarePaginator;
7	use Livewire\Attributes\Layout;
8	use Livewire\Attributes\Title;
9	use Livewire\Attributes\Url;
10	use Livewire\Component;
11	use Livewire\WithPagination;
12	
13	#[Layout('layouts.app')]
14	#[Title('Orders')]
15	class OrderIndex extends Component
16	{
17	    use WithPagination, UsesApiClient;
18	
19	    #[Url] public string $statusFilter = '';
20	    #[Url] public string $search = '';
21	
22	    public function updatedSearch(): void { $this->resetPage(); }
23	    public function updatedStatusFilter(): void { $this->resetPage(); }
24	
25	    /**
26	     * Fetches paginated orders strictly through the REST API. Tenant isolation
27	     * is enforced server-side by OrderApiController::index using the JWT bearer
28	     * token, so this component never queries the database directly.
29	     */
30	    public function render()
31	    {
32	        $user = auth()->user() ?? request()->attributes->get('auth_user');
33	        if (!$user) abort(401);
34	
35	        // The search input is now wired straight through to the API so the
36	        // server-side filter (case-insensitive ILIKE on order_number) does
37	        // the work — no client-side filtering, no double-pagination bugs.
38	        $resp = $this->api()->get('/orders', [
39	            'status'   => $this->statusFilter ?: null,
40	            'search'   => $this->search ?: null,
41	            'page'     => $this->getPage(),
42	            'per_page' => 15,
43	        ]);
44	
45	        $payload = $resp->successful() ? $resp->json() : ['data' => [], 'total' => 0, 'current_page' => 1, 'last_page' => 1, 'per_page' => 15];
46	
47	        $orders = new LengthAwarePaginator(
48	            items: $payload['data'] ?? [],
49	            total: $payload['total'] ?? 0,
50	            perPage: $payload['per_page'] ?? 15,
51	            currentPage: $payload['current_page'] ?? 1,
52	            options: ['path' => request()->url()],
53	        );
54	
55	        return view('livewire.orders.order-index', ['orders' => $orders]);
56	    }
57	}
