3	namespace App\Api\Controllers;
4	
5	use App\Api\Resources\OrderResource;
6	use App\Application\Services\BookingService;
7	use App\Application\Services\SettlementService;
8	use App\Domain\Models\Order;
9	use App\Domain\Models\StaffProfile;
10	use App\Domain\Models\User;
11	use Illuminate\Http\JsonResponse;
12	use Illuminate\Http\Request;
13	use Illuminate\Routing\Controller;
14	use Illuminate\Support\Facades\DB;
15	use Illuminate\Support\Facades\Gate;
16	
17	class OrderApiController extends Controller
18	{
19	    public function __construct(
20	        private readonly BookingService $booking,
21	        private readonly SettlementService $settlement,
22	    ) {}
23	
24	    public function index(Request $request): JsonResponse
25	    {
26	        $user = $request->attributes->get('auth_user');
27	        $isApprovalQueueViewer = $this->canApproveOrders($user);
28	
29	        $orders = Order::query()
30	            // Visibility scope:
31	            //   admin                       → every order
32	            //   staff w/ complete profile   → own + attributed AS GROUP-LEADER
33	            //                                  + any 'pending' order anywhere
34	            //                                  (the shared approval queue)
35	            //   anyone else                 → only own + attributed
36	            ->when(!$user->isAdmin(), fn ($q) => $q->where(function ($q) use ($user, $isApprovalQueueViewer) {
37	                $q->where('user_id', $user->id)
38	                  ->orWhere('group_leader_id', $user->id);
39	                if ($isApprovalQueueViewer) {
40	                    // The OR branch reflects the operational queue model:
41	                    // any pending order is fair game for an on-shift staff
42	                    // member, regardless of who placed it.
43	                    $q->orWhere('status', 'pending');
44	                }
45	            }))
46	            ->when($request->query('status'), fn ($q, $s) => $q->where('status', $s))
47	            // The Livewire OrderIndex component sends the ?search query
48	            // parameter; reject any non-string value at the boundary so
49	            // we cannot leak SQL through the LIKE pattern, then run a
50	            // case-insensitive partial match against the order number.
51	            ->when($request->query('search'), function ($q, $s) {
52	                $needle = trim((string) $s);
53	                if ($needle === '') return $q;
54	                return $q->where('order_number', 'ilike', '%' . $needle . '%');
55	            })
56	            ->orderByDesc('created_at')
57	            ->paginate((int) $request->query('per_page', 15));
58	
59	        // Apply the resource transformer to whitelist columns and preserve pagination meta.
60	        return response()->json([
61	            'data' => OrderResource::collection($orders->items()),
62	            'current_page' => $orders->currentPage(),
63	            'last_page'    => $orders->lastPage(),
64	            'per_page'     => $orders->perPage(),
65	            'total'        => $orders->total(),
66	        ]);
67	    }
68	
69	    public function show(Request $request, int $id): JsonResponse
70	    {
71	        $order = Order::with(['lineItems', 'refunds'])->findOrFail($id);
72	        Gate::authorize('view', $order);
73	
74	        return response()->json(['data' => new OrderResource($order)]);
75	    }
76	
77	    public function store(Request $request): JsonResponse
78	    {
79	        $request->validate([
80	            'line_items' => 'required|array|min:1',
81	            'line_items.*.bookable_item_id' => 'required|exists:bookable_items,id',
82	            'line_items.*.booking_date' => 'required|date',
83	            'line_items.*.quantity' => 'integer|min:1',
84	            'line_items.*.start_time' => 'nullable|date_format:H:i',
85	            'line_items.*.end_time' => 'nullable|date_format:H:i|after:line_items.*.start_time',
86	            'coupon_code' => 'nullable|string',
87	            'notes' => 'nullable|string|max:1000',
88	            'group_leader_id' => 'nullable|exists:users,id',
89	            'service_area_id' => 'nullable|exists:service_areas,id',
90	        ]);
91	
92	        $user = $request->attributes->get('auth_user');
93	
94	        $order = $this->booking->createOrder(
95	            userId: $user->id,
96	            lineItems: $request->input('line_items'),
97	            groupLeaderId: $request->input('group_leader_id'),
98	            serviceAreaId: $request->input('service_area_id'),
99	            couponCode: $request->input('coupon_code'),
100	            notes: $request->input('notes'),
101	        );
102	
103	        return response()->json([
104	            'data' => new OrderResource($order->load(['lineItems'])),
105	            'message' => 'Order created.',
106	        ], 201);
107	    }
108	
109	    public function transition(Request $request, int $id): JsonResponse
110	    {
111	        $request->validate([
112	            'status' => 'required|string|in:pending,confirmed,checked_in,checked_out,completed,cancelled',
113	            'reason' => 'nullable|string|max:500',
114	        ]);
115	
116	        $order = Order::findOrFail($id);
117	        Gate::authorize('transition', [$order, $request->input('status')]);
118	
119	        $order = $this->booking->transitionOrder($order, $request->input('status'), $request->input('reason'));
120	
121	        return response()->json(['data' => new OrderResource($order)]);
122	    }
123	
124	    public function refund(Request $request, int $id): JsonResponse
125	    {
126	        $request->validate(['reason' => 'nullable|string|max:500']);
127	
128	        // Refund processing must be atomic and idempotent. We:
129	        //   1. Open a transaction.
130	        //   2. Re-fetch the order with `lockForUpdate()` so concurrent
131	        //      callers serialise on the row.
132	        //   3. Re-evaluate the policy INSIDE the lock — the freshly
133	        //      loaded `refunded_at` makes the duplicate branch a clean
134	        //      403 instead of an exception or a double-pay.
135	        //   4. Stamp `refunded_at` BEFORE delegating to the service so
136	        //      any later code path observes the row as already refunded.
137	        // The lockForUpdate ensures a second concurrent request blocks
138	        // until this transaction commits, then sees `refunded_at != null`
139	        // and is rejected by the policy gate above.
140	        return DB::transaction(function () use ($request, $id) {
141	            $order = Order::lockForUpdate()->findOrFail($id);
142	
143	            // State-gate + idempotency live in the policy. Re-running it
144	            // here under the lock makes the check race-free.
145	            Gate::authorize('refund', $order);
146	
147	            $refund = $this->settlement->processRefund($order, $request->input('reason'));
148	
149	            // Stamp the idempotency guard. The service also flips
150	            // status → 'refunded', but the timestamp is the canonical
151	            // single-shot marker so the policy can reject duplicates
152	            // even if a future code path opens a new status branch.
153	            $order->update(['refunded_at' => now()]);
154	
155	            return response()->json(['data' => $refund, 'message' => 'Refund processed.']);
156	        });
157	    }
158	
159	    /**
160	     * True when the user is on the staff approval roster: explicit 'staff'
161	     * role with a complete profile. Centralised so the index scope and any
162	     * future helpers stay aligned with OrderPolicy::transition()'s rules.
163	     */
164	    private function canApproveOrders(User $user): bool
165	    {
166	        if ($user->role !== 'staff') return false;
167	        $profile = StaffProfile::where('user_id', $user->id)->first();
168	        return $profile !== null && $profile->isComplete();
169	    }
170	
171	    public function markUnavailable(Request $request, int $id): JsonResponse
172	    {
173	        $order = Order::findOrFail($id);
174	        Gate::authorize('markUnavailable', $order);
175	
176	        $order->update(['staff_marked_unavailable' => true]);
177	
178	        return response()->json(['message' => 'Order marked as staff unavailable.']);
179	    }
180	}
