32	/*
33	|--------------------------------------------------------------------------
34	| Authenticated routes (JWT required)
35	|--------------------------------------------------------------------------
36	*/
37	Route::middleware('jwt.auth')->group(function () {
38	
39	    // Auth lifecycle
40	    Route::post('/auth/logout', [AuthController::class, 'logout']);
41	    Route::get('/auth/me', [AuthController::class, 'me']);
42	
43	    // Staff profile (self-service)
