49	
50	    // ── Read endpoints (any authenticated user) ─────────────────────
51	
52	    Route::apiResource('service-areas', ServiceAreaController::class)->only(['index', 'show']);
53	    Route::apiResource('roles', RoleController::class)->only(['index', 'show']);
54	    Route::apiResource('resources', ResourceController::class)->only(['index', 'show']);
55	    Route::apiResource('pricing-baselines', PricingBaselineController::class)->only(['index', 'show']);
56	
57	    // Booking catalog, availability, pricing (any authenticated user)
58	    Route::get('/bookings/items', [BookingApiController::class, 'items']);
59	    Route::post('/bookings/check-availability', [BookingApiController::class, 'checkAvailability']);
60	    Route::post('/bookings/calculate-totals', [BookingApiController::class, 'calculateTotals']);
61	    Route::post('/bookings/validate-coupon', [BookingApiController::class, 'validateCoupon']);
62	
63	    // Orders — any authenticated user can create, view own, and manage own
64	    Route::get('/orders', [OrderApiController::class, 'index']);
65	    Route::get('/orders/{id}', [OrderApiController::class, 'show']);
66	    Route::post('/orders', [OrderApiController::class, 'store']);
67	    Route::post('/orders/{id}/transition', [OrderApiController::class, 'transition']);
68	    Route::post('/orders/{id}/refund', [OrderApiController::class, 'refund']);
69	    Route::post('/orders/{id}/mark-unavailable', [OrderApiController::class, 'markUnavailable']);
70	
71	    // Attachment download (authorized in controller)
72	    Route::get('/attachments/{id}/download', [AttachmentController::class, 'download']);
73	
74	    // Exports (scoped by user in controller)
75	    Route::post('/exports', [ExportApiController::class, 'export']);
76	
77	    // ── Staff+ operational write surface ────────────────────────────
78	    // Limited to operational concerns (attachments). Foundational
79	    // entity writes are admin-only — see the admin block below.
80	    Route::middleware(['role:staff', 'profile.complete'])->group(function () {
81	        // Attachment upload
82	        Route::post('/attachments', [AttachmentController::class, 'upload']);
83	    });
84	
85	    // ── Settlement read access — staff+ (row-level scoped) ─────────
86	    //
87	    // Read access to financial summaries is gated by ROLE only — the
88	    // profile.complete middleware is reserved for *operational* actions
89	    // (check-in / check-out / approvals). A staff member with an
90	    // incomplete profile must still be able to inspect their own
91	    // settlement summary; SettlementService applies strict row-level
92	    // scoping so cross-tenant data never leaks regardless of profile state.
93	    Route::middleware('role:staff')->group(function () {
94	        Route::get('/settlements', [SettlementApiController::class, 'index']);
95	        Route::get('/settlements/{id}', [SettlementApiController::class, 'show']);
