12	use Carbon\Carbon;
13	use Illuminate\Support\Facades\DB;
14	
15	class SettlementService
16	{
17	    private const CANCELLATION_FEE_RATE = 0.20; // 20%
18	    private const DISPUTE_HOLD_BUSINESS_DAYS = 3;
19	
20	    /** Allowed settlement cadences. Anything else is rejected at the boundary. */
21	    public const ALLOWED_CYCLE_TYPES = ['weekly', 'biweekly'];
22	
23	    public function __construct(
24	        private readonly AuditLogRepositoryInterface $audit,
25	    ) {}
26	
27	    /**
28	     * Process a refund for an order.
29	     * Full refund within 15 min, 20% fee after, waive if staff-marked unavailable.
30	     */
31	    public function processRefund(Order $order, ?string $reason = null): Refund
32	    {
33	        $originalAmount = (float) $order->total;
34	        $isFullRefund = $order->isWithinFullRefundWindow();
35	        $staffOverride = (bool) $order->staff_marked_unavailable;
36	
37	        if ($isFullRefund || $staffOverride) {
38	            $fee = 0;
39	        } else {
40	            $fee = round($originalAmount * self::CANCELLATION_FEE_RATE, 2);
41	        }
42	
43	        $refundAmount = round($originalAmount - $fee, 2);
44	
45	        $refund = Refund::create([
46	            'order_id'                   => $order->id,
47	            'original_amount'            => $originalAmount,
48	            'cancellation_fee'           => $fee,
49	            'refund_amount'              => $refundAmount,
50	            'reason'                     => $reason,
51	            'is_full_refund'             => $isFullRefund || $staffOverride,
52	            'staff_unavailable_override' => $staffOverride,
53	            'status'                     => 'processed',
54	            'processed_at'               => now(),
55	        ]);
56	
57	        $order->update(['status' => 'refunded']);
58	
59	        $this->audit->log('refund_processed', 'Order', $order->id, null, [
60	            'refund_amount' => $refundAmount, 'fee' => $fee,
61	        ]);
62	
63	        return $refund;
64	    }
65	
66	    /**
67	     * Generate a settlement for a date range with an explicit billing cadence.
68	     *
69	     * @param  string  $periodStart  ISO date (YYYY-MM-DD)
70	     * @param  string  $periodEnd    ISO date (YYYY-MM-DD)
71	     * @param  string  $cycleType    'weekly' or 'biweekly'. Defaults to weekly
72	     *                               only because the persisted column has the
73	     *                               same default; callers SHOULD pass it
74	     *                               explicitly so reports stay coherent.
75	     *
76	     * @throws \InvalidArgumentException if $cycleType is not allowed
77	     */
78	    public function generateSettlement(string $periodStart, string $periodEnd, string $cycleType = 'weekly'): Settlement
79	    {
80	        if (!in_array($cycleType, self::ALLOWED_CYCLE_TYPES, true)) {
81	            throw new \InvalidArgumentException(
82	                "cycle_type must be one of: " . implode(', ', self::ALLOWED_CYCLE_TYPES)
83	            );
84	        }
85	
86	        return DB::transaction(function () use ($periodStart, $periodEnd, $cycleType) {
87	            $orders = Order::whereBetween('confirmed_at', [$periodStart, $periodEnd . ' 23:59:59'])
88	                ->whereIn('status', ['completed', 'checked_out'])
89	                ->get();
90	
91	            $refunds = Refund::whereHas('order', fn ($q) =>
92	                $q->whereBetween('confirmed_at', [$periodStart, $periodEnd . ' 23:59:59'])
93	            )->where('status', 'processed')->get();
94	
95	            $gross = $orders->sum('total');
96	            $refundTotal = $refunds->sum('refund_amount');
97	
98	            $settlement = Settlement::create([
99	                'reference'    => 'STL-' . date('Ymd') . '-' . str_pad(mt_rand(1, 999), 3, '0', STR_PAD_LEFT),
100	                'period_start' => $periodStart,
101	                'period_end'   => $periodEnd,
102	                'gross_amount' => $gross,
103	                'refund_total' => $refundTotal,
104	                'net_amount'   => $gross - $refundTotal,
105	                'order_count'  => $orders->count(),
106	                'refund_count' => $refunds->count(),
107	                'status'       => 'draft',
108	                'cycle_type'   => $cycleType,
109	            ]);
110	
111	            // Generate commissions tied to THIS settlement, propagating the
112	            // cycle_type so weekly vs biweekly cadences are reported correctly.
113	            $this->calculateCommissions($periodStart, $periodEnd, $cycleType, $settlement->id);
114	
115	            $this->audit->log('settlement_generated', 'Settlement', $settlement->id, null, [
116	                'cycle_type' => $cycleType,
117	                'period_start' => $periodStart,
118	                'period_end' => $periodEnd,
119	            ]);
120	
121	            return $settlement;
122	        });
123	    }
124	
125	    /**
126	     * Calculate commissions for group leaders within a date range.
127	     */
128	    public function calculateCommissions(string $cycleStart, string $cycleEnd, string $cycleType = 'weekly', ?int $settlementId = null): array
129	    {
130	        if (!in_array($cycleType, self::ALLOWED_CYCLE_TYPES, true)) {
131	            throw new \InvalidArgumentException(
132	                "cycle_type must be one of: " . implode(', ', self::ALLOWED_CYCLE_TYPES)
133	            );
134	        }
135	
136	        // Eligible group leader IDs: users currently holding the group-leader (or admin) role
137	        // AND active. This prevents stale or demoted assignments from earning commission.
138	        $eligibleLeaderIds = User::query()
139	            ->whereIn('role', ['group-leader', 'admin'])
140	            ->where('is_active', true)
141	            ->pluck('id')
142	            ->all();
143	
144	        $orders = Order::with(['refunds', 'lineItems.bookableItem'])
145	            ->whereBetween('confirmed_at', [$cycleStart, $cycleEnd . ' 23:59:59'])
146	            ->whereIn('status', ['completed', 'checked_out'])
147	            ->whereNotNull('group_leader_id')
148	            ->whereIn('group_leader_id', $eligibleLeaderIds)
149	            ->get()
150	            ->filter(function (Order $o) {
151	                // Enforce service-area assignment: a commission accrues only when the
152	                // group leader holds an active GroupLeaderAssignment for the order's
153	                // service area. Admins always pass. Orders with no service area are
154	                // treated as out-of-scope for assignment-based commissions.
155	                $leader = User::find($o->group_leader_id);
156	                if ($leader && $leader->role === 'admin') return true;
157	                if (!$o->service_area_id) return false;
158	
159	                $assignment = GroupLeaderAssignment::where('user_id', $o->group_leader_id)
160	                    ->where('service_area_id', $o->service_area_id)
161	                    ->where('is_active', true)
162	                    ->first();
163	                if (!$assignment) return false;
164	
165	                // Location binding (mirrors BookingService::createOrder).
166	                // A NULL/blank assignment.location covers the entire
167	                // service area; a set location requires every line item's
168	                // bookable_item.location to match exactly. Items with a
169	                // NULL location are NOT covered by a location-bound
170	                // assignment, so the order is excluded from commission.
171	                $assigned = $this->normalizeLocation($assignment->location);
172	                if ($assigned === null) return true;
173	
174	                foreach ($o->lineItems as $li) {
175	                    $itemLoc = $this->normalizeLocation(optional($li->bookableItem)->location);
176	                    if ($itemLoc !== $assigned) return false;
177	                }
178	                return true;
179	            })
180	            ->groupBy('group_leader_id');
181	
182	        $holdUntil = $this->addBusinessDays(Carbon::parse($cycleEnd), self::DISPUTE_HOLD_BUSINESS_DAYS);
183	        $commissions = [];
184	
185	        foreach ($orders as $leaderId => $leaderOrders) {
186	            // Only revenue from orders that have actually been settled (refunds netted)
187	            $revenue = $leaderOrders->sum(function ($o) {
188	                $refunded = (float) optional($o->refunds)->sum('refund_amount');
189	                return max(0, (float) $o->total - $refunded);
190	            });
191	            if ($revenue <= 0) continue;
192	
193	            $commission = Commission::updateOrCreate(
194	                ['group_leader_id' => $leaderId, 'cycle_start' => $cycleStart, 'cycle_end' => $cycleEnd],
195	                [
196	                    'settlement_id'      => $settlementId,
197	                    'cycle_type'         => $cycleType,
198	                    'attributed_revenue' => $revenue,
199	                    'commission_rate'    => 0.1000,
200	                    'commission_amount'  => round($revenue * 0.10, 2),
201	                    'order_count'        => $leaderOrders->count(),
202	                    'status'             => 'held',
203	                    'hold_until'         => $holdUntil,
204	                ],
205	            );
206	
207	            $commissions[] = $commission;
208	        }
209	
210	        return $commissions;
211	    }
