213	    private function addBusinessDays(Carbon $start, int $days): Carbon
214	    {
215	        $date = $start->copy();
216	        $added = 0;
217	        while ($added < $days) {
218	            $date->addDay();
219	            if (!$date->isWeekend()) $added++;
220	        }
221	        return $date;
222	    }
