224	    /**
225	     * Read-side: list settlements visible to a user with strict row-level scoping.
226	     *
227	     *   - admin        → every settlement
228	     *   - group-leader → settlements where they hold at least one commission row
229	     *   - staff        → settlements whose period covers at least one order they
230	     *                    personally placed (Order.user_id = staff.id). This is
231	     *                    the staff-summary access mandated by the spec, and the
232	     *                    SQL `whereHas` ensures rows the staff has no link to
233	     *                    never appear in the result set (no broad leakage).
234	     *   - regular user → no access (the controller layer enforces this)
235	     */
236	    public function listSettlementsForUser(User $user, int $perPage = 10)
237	    {
238	        return $this->applyRowLevelScope(
239	            Settlement::query()->orderByDesc('period_end'),
240	            $user,
241	        )->paginate($perPage);
242	    }
