275	     * here so the index, show, and export endpoints share one source of truth
276	     * for who can see what.
277	     */
278	    private function applyRowLevelScope($query, User $user)
279	    {
280	        if ($user->isAdmin()) {
281	            return $query;
282	        }
283	        if ($user->role === 'group-leader') {
284	            return $query->whereHas('commissions', fn ($cq) => $cq->where('group_leader_id', $user->id));
285	        }
286	        if ($user->role === 'staff') {
