289	                    ->from('orders')
290	                    ->where('orders.user_id', $user->id)
291	                    ->whereColumn('orders.confirmed_at', '>=', 'settlements.period_start')
292	                    ->whereColumn('orders.confirmed_at', '<=', \Illuminate\Support\Facades\DB::raw("settlements.period_end + interval '1 day'"));
