326	                $sq->whereExists(function ($sub) use ($user) {
327	                    $sub->select(\Illuminate\Support\Facades\DB::raw(1))
328	                        ->from('orders')
329	                        ->where('orders.user_id', $user->id)
330	                        ->whereColumn('orders.confirmed_at', '>=', 'settlements.period_start')
331	                        ->whereColumn('orders.confirmed_at', '<=', \Illuminate\Support\Facades\DB::raw("settlements.period_end + interval '1 day'"));
332	                });
333	            })->get();
334	        }
335	
336	        return $q->whereRaw('1 = 0')->get();
337	    }
