353	     * Reconcile: verify all order totals match line items and refunds are accounted.
354	     */
355	    public function reconcile(Settlement $settlement): array
356	    {
357	        $orders = Order::whereBetween('confirmed_at', [$settlement->period_start, $settlement->period_end->endOfDay()])
358	            ->whereIn('status', ['completed', 'checked_out'])
359	            ->with('lineItems')
360	            ->get();
361	
362	        $discrepancies = [];
363	        foreach ($orders as $order) {
364	            $lineTotal = $order->lineItems->sum('line_total');
365	            $expected = round($lineTotal - (float) $order->discount_amount, 2);
366	            if (abs((float) $order->total - $expected) > 0.01) {
367	                $discrepancies[] = [
368	                    'order_id' => $order->id,
369	                    'order_number' => $order->order_number,
370	                    'recorded_total' => $order->total,
371	                    'calculated_total' => $expected,
372	                    'difference' => round((float) $order->total - $expected, 2),
373	                ];
374	            }
375	        }
376	
377	        if (empty($discrepancies)) {
378	            $settlement->update(['status' => 'reconciled']);
379	        }
380	
381	        return $discrepancies;
382	    }
383	
384	    /**
385	     * Normalize a location string for binding comparisons. Returns null
386	     * for blank/whitespace values so callers can distinguish "no
387	     * location constraint" from a real value.
388	     */
389	    private function normalizeLocation(?string $location): ?string
390	    {
391	        if ($location === null) return null;
392	        $trimmed = trim($location);
393	        if ($trimmed === '') return null;
394	        return mb_strtolower($trimmed);
395	    }
396	}
