1	<?php
2	
3	namespace App\Livewire\Concerns;
4	
5	use App\Domain\Models\User;
6	use Illuminate\Contracts\Http\Kernel as HttpKernel;
7	use Illuminate\Http\Request as IlluminateRequest;
8	use Symfony\Component\HttpFoundation\Response as SymfonyResponse;
9	
10	/**
11	 * Internal-dispatch API client for Livewire components.
12	 *
13	 * Why not real HTTP? Two reasons:
14	 *
15	 *   1. PHPUnit runs the entire suite in-process — there is no nginx
16	 *      and no listening port, so a real `Http::baseUrl(...)->get()`
17	 *      from a Livewire component dies with cURL "connection refused".
18	 *      Even if a server were running, it would be talking to a
19	 *      different DB connection (the test runner uses a separate
20	 *      schema) so authentication state would not be visible.
21	 *
22	 *   2. In production, the Livewire component is already inside a
23	 *      Laravel HTTP request. A sub-request through the kernel reuses
24	 *      the same DB connection, the same container bindings, and the
25	 *      same authenticated user without paying the network round-trip
26	 *      tax — and authorization parity is preserved because we route
27	 *      through the SAME api.php routes the REST clients use.
28	 *
29	 * The api() trait still gives Livewire components the same surface
30	 * (`->get('/path')`, `->post('/path', $body)`, `->successful()`,
31	 * `->json()`) but the dispatch is in-process. The auth user is
32	 * threaded via the `auth_user` request attribute that the existing
33	 * jwt.auth middleware also sets, so downstream code is identical.
34	 */
35	trait UsesApiClient
36	{
37	    protected function api(): InternalApiClient
38	    {
39	        return new InternalApiClient($this->resolveAuthUser());
40	    }
41	
42	    /**
43	     * Find the user this Livewire request is acting on behalf of.
44	     * In production this comes from the WebSessionAuth middleware
45	     * which sets `auth_user` on the current request. In tests it
46	     * comes from `actingAs($user)` which sets the auth guard.
47	     */
48	    private function resolveAuthUser(): ?User
49	    {
50	        $current = request()->attributes->get('auth_user');
51	        if ($current instanceof User) return $current;
52	
53	        $authed = auth()->user();
54	        return $authed instanceof User ? $authed : null;
55	    }
56	
57	    /**
58	     * Effective permission slugs for the authenticated user, fetched
59	     * through GET /auth/me. Cached on the component instance so a
60	     * single render only issues one sub-request. The blade can then
61	     * conditionally render buttons via:
62	     *
63	     *   @if(in_array('settlements.finalize', $effectivePermissions))
64	     *
65	     * which mirrors EXACTLY the slug enforced by the permission:*
66	     * middleware on the corresponding API mutation route.
67	     */
68	    protected ?array $cachedEffectivePermissions = null;
69	
70	    protected function effectivePermissions(): array
71	    {
72	        if ($this->cachedEffectivePermissions !== null) {
73	            return $this->cachedEffectivePermissions;
74	        }
75	        $resp = $this->api()->get('/auth/me');
76	        if (!$resp->successful()) {
77	            return $this->cachedEffectivePermissions = [];
78	        }
79	        return $this->cachedEffectivePermissions = (array) ($resp->json('data.effective_permissions') ?? []);
80	    }
81	}
82	
83	/**
84	 * Lightweight in-process API client. Mimics the parts of
85	 * Illuminate\Http\Client\PendingRequest the Livewire layer uses.
86	 */
87	class InternalApiClient
88	{
89	    public function __construct(private readonly ?User $authUser) {}
90	
91	    public function get(string $path, array $query = []): InternalApiResponse
92	    {
93	        return $this->dispatch('GET', $path, $query);
94	    }
95	
96	    public function post(string $path, array $body = []): InternalApiResponse
97	    {
98	        return $this->dispatch('POST', $path, [], $body);
99	    }
100	
101	    public function put(string $path, array $body = []): InternalApiResponse
102	    {
103	        return $this->dispatch('PUT', $path, [], $body);
104	    }
105	
106	    private function dispatch(string $method, string $path, array $query = [], array $body = []): InternalApiResponse
107	    {
108	        $url = '/api' . $path;
109	        if (!empty($query)) {
110	            $url .= (str_contains($url, '?') ? '&' : '?') . http_build_query($query);
111	        }
112	
113	        $server = [
114	            'HTTP_ACCEPT'  => 'application/json',
115	            'CONTENT_TYPE' => 'application/json',
116	        ];
117	
118	        $content = !empty($body) ? json_encode($body) : null;
119	
120	        $request = IlluminateRequest::create($url, $method, [], [], [], $server, $content);
121	
122	        // Bypass jwt.auth by pre-stamping the auth_user attribute and
123	        // setting the auth guard. The jwt.auth middleware short-circuits
124	        // when an auth_user is already present. The kernel still runs
125	        // every other middleware — role:*, permission:*, profile.complete
126	        // — so authorization is enforced identically to a REST request.
127	        if ($this->authUser !== null) {
128	            $request->attributes->set('auth_user', $this->authUser);
129	            app('auth')->setUser($this->authUser);
130	        }
131	
132	        // Livewire's testing harness binds `middleware.disable=true`
133	        // so its OWN component renders skip middleware. That flag is
134	        // a singleton on the container and leaks into ANY downstream
135	        // kernel->handle() call we make from inside the component.
136	        // Locally invert it for the duration of our sub-request so
137	        // jwt.auth, role:*, permission:* and friends actually run —
138	        // then restore the previous binding so we don't disturb the
139	        // outer Livewire test that depends on it.
140	        $previousDisable = app()->bound('middleware.disable')
141	            ? app()->make('middleware.disable')
142	            : null;
143	        app()->instance('middleware.disable', false);
144	
145	        try {
146	            /** @var HttpKernel $kernel */
147	            $kernel = app(HttpKernel::class);
148	            $response = $kernel->handle($request);
149	        } catch (\Throwable $e) {
150	            // Convert exceptions into the response codes the same
151	            // request would yield in production. Laravel's exception
152	            // handler does this for top-level requests but not always
153	            // for in-process sub-requests, so we map the common
154	            // domain exceptions ourselves and fall back to the
155	            // framework handler for everything else.
156	            $response = $this->renderExceptionResponse($e, $request);
157	        } finally {
158	            if ($previousDisable === null) {
159	                app()->forgetInstance('middleware.disable');
160	            } else {
161	                app()->instance('middleware.disable', $previousDisable);
162	            }
163	        }
164	
165	        return new InternalApiResponse($response);
166	    }
167	
168	    private function renderExceptionResponse(\Throwable $e, IlluminateRequest $request): SymfonyResponse
169	    {
170	        if ($e instanceof \Illuminate\Database\Eloquent\ModelNotFoundException
171	            || $e instanceof \Symfony\Component\HttpKernel\Exception\NotFoundHttpException) {
172	            return response()->json(['message' => 'Resource not found.'], 404);
173	        }
174	        if ($e instanceof \Illuminate\Validation\ValidationException) {
175	            return response()->json([
176	                'message' => $e->getMessage(),
177	                'errors'  => $e->errors(),
178	            ], 422);
179	        }
180	        if ($e instanceof \Symfony\Component\HttpKernel\Exception\HttpExceptionInterface) {
181	            return response()->json(['message' => $e->getMessage()], $e->getStatusCode());
182	        }
183	        // Re-throw anything we don't recognise so the surrounding test
184	        // (or production exception handler) sees the real error rather
185	        // than a swallowed 500.
186	        throw $e;
187	    }
188	}
189	
190	/**
191	 * Lightweight response wrapper that mimics the parts of
192	 * Illuminate\Http\Client\Response the Livewire layer uses.
193	 */
194	class InternalApiResponse
195	{
196	    public function __construct(private readonly SymfonyResponse $response) {}
197	
198	    public function status(): int
199	    {
200	        return $this->response->getStatusCode();
201	    }
202	
203	    public function successful(): bool
204	    {
205	        return $this->status() < 300;
206	    }
207	
208	    public function failed(): bool
209	    {
210	        return !$this->successful();
211	    }
212	
213	    public function json(?string $key = null, mixed $default = null): mixed
214	    {
215	        $decoded = json_decode($this->response->getContent(), true);
216	        if (!is_array($decoded)) return $key === null ? [] : $default;
217	        if ($key === null) return $decoded;
218	        return data_get($decoded, $key, $default);
219	    }
220	
221	    /**
222	     * Raw response body (used by exporters that stream CSV/PDF).
223	     */
224	    public function body(): string
225	    {
226	        return (string) $this->response->getContent();
227	    }
228	}
