3	namespace App\Api\Controllers;
4	
5	use App\Application\Services\AttachmentService;
6	use App\Domain\Models\Attachment;
7	use App\Domain\Policies\AttachmentPolicy;
8	use App\Infrastructure\Export\ImageCompressor;
9	use Illuminate\Http\JsonResponse;
10	use Illuminate\Http\Request;
11	use Illuminate\Routing\Controller;
12	use Illuminate\Support\Facades\Log;
13	use Illuminate\Support\Facades\Storage;
14	
15	class AttachmentController extends Controller
16	{
17	    public function __construct(private readonly AttachmentService $service) {}
18	
19	    public function upload(Request $request): JsonResponse
20	    {
21	        $request->validate([
22	            'file' => 'required|file|max:20480',
23	            'attachable_type' => 'required|string|max:100',
24	            'attachable_id' => 'required|integer|min:1',
25	        ]);
26	
27	        $user = $request->attributes->get('auth_user');
28	
29	        // 1) Whitelist attachable_type — reject unknown classes outright.
30	        $fqcn = AttachmentPolicy::canonicalAttachableType($request->input('attachable_type'));
31	        if ($fqcn === null) {
32	            Log::warning('attachment.upload.rejected_type', [
33	                'user_id' => $user?->id,
34	                'attempted_type' => $request->input('attachable_type'),
35	            ]);
36	            return response()->json(['message' => 'Invalid attachable type.'], 422);
37	        }
38	
39	        // 2) Existence check — the attachable entity must exist.
40	        $entity = $fqcn::find((int) $request->input('attachable_id'));
41	        if ($entity === null) {
42	            return response()->json(['message' => 'Attachable entity not found.'], 404);
43	        }
44	
45	        // 3) Object-level authorization — must be allowed to attach to THIS entity.
46	        if (!AttachmentPolicy::canAttachTo($user, $entity)) {
47	            Log::warning('attachment.upload.denied', [
48	                'user_id' => $user->id,
49	                'attachable_type' => $fqcn,
50	                'attachable_id' => $entity->id,
51	            ]);
52	            return response()->json(['message' => 'Forbidden.'], 403);
53	        }
54	
55	        // 4) Persist file only after the above checks pass.
56	        $file = $request->file('file');
57	        $path = $file->store('attachments', 'local');
58	        $fullPath = Storage::disk('local')->path($path);
59	
60	        $mime = $file->getMimeType();
61	        if (in_array($mime, ['image/jpeg', 'image/png', 'image/webp'])) {
62	            ImageCompressor::compress($fullPath);
63	        }
64	
65	        $sha256 = hash_file('sha256', $fullPath);
66	        $sizeBytes = filesize($fullPath);
67	
68	        try {
69	            $attachment = $this->service->create(
70	                attachableType: $fqcn,
71	                attachableId: (int) $entity->id,
72	                originalFilename: $file->getClientOriginalName(),
73	                storedPath: $path,
74	                mimeType: $mime,
75	                sizeBytes: $sizeBytes,
76	                sha256Fingerprint: $sha256,
77	                uploadedBy: $user->id,
78	            );
79	        } catch (\Throwable $e) {
80	            // Roll back the stored file if metadata persistence/validation fails.
81	            Storage::disk('local')->delete($path);
82	            return response()->json(['message' => $e->getMessage()], 422);
83	        }
84	
85	        return response()->json(['data' => $attachment, 'message' => 'File uploaded.'], 201);
86	    }
87	
88	    public function download(Request $request, int $id)
89	    {
90	        $attachment = Attachment::findOrFail($id);
91	        $user = $request->attributes->get('auth_user');
92	
93	        // Object-level authorization: admin OR uploader OR allowed-to-attach to the parent entity.
94	        if (!$user->isAdmin() && $attachment->uploaded_by !== $user->id) {
95	            $fqcn = AttachmentPolicy::canonicalAttachableType((string) $attachment->attachable_type);
96	            if ($fqcn === null) {
97	                return response()->json(['message' => 'Forbidden.'], 403);
98	            }
99	            $entity = $fqcn::find($attachment->attachable_id);
100	            if (!$entity || !AttachmentPolicy::canAttachTo($user, $entity)) {
101	                return response()->json(['message' => 'Forbidden.'], 403);
102	            }
103	        }
104	
105	        if (!Storage::disk('local')->exists($attachment->stored_path)) {
106	            return response()->json(['message' => 'File not found.'], 404);
107	        }
108	
109	        return Storage::disk('local')->download(
110	            $attachment->stored_path,
111	            $attachment->original_filename,
112	        );
113	    }
114	}
